import React, { useEffect, useRef } from 'react';
import Lottie from 'lottie-web';
import './Home.css';
import logo1 from './assets/apple-logo.svg';
import animationData from './assets/Ai.json';
import logo2 from './assets/android-logo.svg';

const Home = () => {
  const animationContainer = useRef(null);

  useEffect(() => {
    Lottie.loadAnimation({
      container: animationContainer.current,
      renderer: 'svg',
      loop: true,
      autoplay: true,
      animationData: animationData
    });
  }, []);

  return (
    <div className="home-container">
      <div className="logos">
        <img src={logo1} alt="Apple Logo" className="logo" />
        <img src={logo2} alt="Android Logo" className="logo" />
      </div>
      <h1>Mac Keating.ai</h1>
      <div ref={animationContainer} className="lottie-container"></div>
      <h2>Providing AI Solutions</h2>
    </div>
  );
};

export default Home;
